SELECT feature_area FROM (
  SELECT DISTINCT feature_area FROM pipemind.project_signals
  WHERE feature_area IS NOT NULL
  UNION ALL
  SELECT NULL::text AS feature_area WHERE NOT EXISTS (
    SELECT 1 FROM pipemind.project_signals WHERE feature_area IS NOT NULL
  )
) t;

