// F-02.2: identify which known feature area the client's question is about, so we
// know who to ask. Word-boundary substring match against already-known area names
// (from project_signals) — no LLM call needed, and no Jira assignee data used (SC-17
// forbids extracting individual attribution from Jira for any purpose).
const rows = $input.all();
const areas = rows.map(r => String(r.json.feature_area || '')).filter(Boolean);
const question = String($('Assemble Context').first().json.client_question || '').toLowerCase();

const hasWordBoundary = (haystack, needle) => {
  const idx = haystack.indexOf(needle);
  if (idx === -1) return false;
  const pre = idx === 0 || !/[a-z0-9]/.test(haystack[idx - 1]);
  const post = idx + needle.length >= haystack.length || !/[a-z0-9]/.test(haystack[idx + needle.length]);
  return pre && post;
};

let matched = null;
for (const area of areas) {
  if (hasWordBoundary(question, area.toLowerCase())) { matched = area; break; }
}

return [{ json: { feature_area: matched } }];

const j = $input.first().json;
if (!j.feature_area) return [];
return $input.all();

const j = $input.first().json;
if (j.feature_area) return [];
return $input.all();

const clockify = $('Check Candidate Scheduled').first().json;
const clockifyOk = clockify.statusCode === 200;
const clockifyBusy = clockifyOk && (clockify.body?.length ?? 0) > 0;

const calRaw = $input.first().json;
let calOk = false, calBusy = false;
try {
  if (calRaw && typeof calRaw.calendars === 'object') {
    calOk = true;
    for (const data of Object.values(calRaw.calendars)) {
      if (Array.isArray(data.busy) && data.busy.some(p => (new Date(p.end) - new Date(p.start)) / 3_600_000 >= 6)) {
        calBusy = true;
      }
    }
  }
} catch (_) {}

// SC-06a: stricter source wins. SC-18-style failsafe: both sources down -> treat as unavailable.
const available = (clockifyOk || calOk) && !clockifyBusy && !calBusy;

if (!available) return [];
return $input.all();

const clockify = $('Check Candidate Scheduled').first().json;
const clockifyOk = clockify.statusCode === 200;
const clockifyBusy = clockifyOk && (clockify.body?.length ?? 0) > 0;

const calRaw = $input.first().json;
let calOk = false, calBusy = false;
try {
  if (calRaw && typeof calRaw.calendars === 'object') {
    calOk = true;
    for (const data of Object.values(calRaw.calendars)) {
      if (Array.isArray(data.busy) && data.busy.some(p => (new Date(p.end) - new Date(p.start)) / 3_600_000 >= 6)) {
        calBusy = true;
      }
    }
  }
} catch (_) {}

const available = (clockifyOk || calOk) && !clockifyBusy && !calBusy;

if (available) return [];
return $input.all();

const question = String($('Assemble Context').first().json.client_question || '')
  .replace(/[\x00-\x1F\x7F]/g, ' ')
  .trim()
  .slice(0, 1000);

const dmChannelId = $('Open Candidate DM Channel').first().json.id || null;

const text = [
  '[Pipemind] Quick question from a client that I could not confidently answer on my own \u2014 could you help?',
  '',
  '"' + question + '"',
  '',
  'Just reply here with what you know. I will turn your reply into an answer for the client, and the team lead approves it before anything is sent \u2014 nothing you say goes to the client directly.'
].join('\n');

// F-02.3: 2 hours from now, capped at end of the working day (EOD_TIME) so a question
// asked late in the day doesn't silently roll a "same working day" deadline into tomorrow.
const now = new Date();
const twoHoursLater = new Date(now.getTime() + 2 * 60 * 60 * 1000);
const eodTime = String($env.EOD_TIME || '17:00');
const eodParts = eodTime.split(':').map(n => parseInt(n, 10) || 0);
const todayEod = new Date(now);
todayEod.setHours(eodParts[0] ?? 17, eodParts[1] ?? 0, 0, 0);
const deadline = twoHoursLater < todayEod ? twoHoursLater : todayEod;

return [{ json: { dm_channel_id: dmChannelId, dm_text: text, deadline_iso: deadline.toISOString() } }];
